    console.log(`Message: ${message}`);
    console.log("");

    // Find parent
    const parentLine = lines.find((l) => l.startsWith("parent: "));
    current = parentLine ? parentLine.substring("parent: ".length) : "NONE";
    if (current === "NONE") break;
  }
}

